import{_ as a,c as o,a1 as t,o as r}from"./chunks/framework.BDxlaA_J.js";const f=JSON.parse('{"title":"Windows Sniffing Tools","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/7-sniffing/X-Windows-Tools.md","filePath":"categories/ethical-hacking-labs/7-sniffing/X-Windows-Tools.md"}'),s={name:"categories/ethical-hacking-labs/7-sniffing/X-Windows-Tools.md"};function n(i,e,l,p,c,d){return r(),o("div",null,e[0]||(e[0]=[t('<h1 id="windows-sniffing-tools" tabindex="-1">Windows Sniffing Tools <a class="header-anchor" href="#windows-sniffing-tools" aria-label="Permalink to &quot;Windows Sniffing Tools&quot;">​</a></h1><h2 id="wireshark" tabindex="-1">Wireshark <a class="header-anchor" href="#wireshark" aria-label="Permalink to &quot;Wireshark&quot;">​</a></h2><p>Wireshark is the world’s foremost and widely-used network protocol analyzer. It lets you see what’s happening on your network at a microscopic level and is the de facto (and often de jure) standard across many commercial and non-profit enterprises, government agencies, and educational institutions.</p><p><a href="https://www.wireshark.org/" target="_blank" rel="noreferrer">https://www.wireshark.org/</a></p><h2 id="cain-abel" tabindex="-1">Cain &amp; Abel <a class="header-anchor" href="#cain-abel" aria-label="Permalink to &quot;Cain &amp; Abel&quot;">​</a></h2><p>Cain &amp; Abel is a very useful security tool used for decryption and decoding of passwords for a wide array of offline programs and network services. Built from the ground up to be extremely helpful to users who have forgotten passwords for some of their most-used apps on their home PC, Cain and Abel features powerful decoding algorithms, extensive decrypting tools, and other.</p><p><a href="https://www.filehorse.com/download-cain-and-abel/" target="_blank" rel="noreferrer">https://www.filehorse.com/download-cain-and-abel/</a></p><p><img src="https://1.bp.blogspot.com/-Cu3iqrOhY8A/TZ7vKOfWMfI/AAAAAAAABkc/xeaZvXMNKCg/s728-e100/537.jpg" alt="cainable"></p><h2 id="smac" tabindex="-1">SMAC <a class="header-anchor" href="#smac" aria-label="Permalink to &quot;SMAC&quot;">​</a></h2><p>SMAC is a powerful and easy-to-use tool for MAC address changer (spoofer). The tool can activate a new MAC address right after changing it automatically.</p><p><a href="https://smac.soft32.com/" target="_blank" rel="noreferrer">https://smac.soft32.com/</a></p><p><img src="https://thegeekpage.com/wp-content/uploads/2016/05/mac-address-changer-tool.gif" alt="smac"></p><h2 id="capsa-network-analyzer" tabindex="-1">Capsa Network Analyzer <a class="header-anchor" href="#capsa-network-analyzer" aria-label="Permalink to &quot;Capsa Network Analyzer&quot;">​</a></h2><p>Capsa Free is a network analyzer freeware for Ethernet monitoring, troubleshooting and analysis. It provides users with great experience to learn how to monitor network activities, pinpoint network problems, enhance network security. <a href="https://www.colasoft.com/capsa-free/" target="_blank" rel="noreferrer">https://www.colasoft.com/capsa-free/</a></p><p><img src="https://www.colasoft.com/images/capsa-8-screenshots/home-dashboard.jpg" alt="capsa"></p><h2 id="omnipeek" tabindex="-1">OmniPeek <a class="header-anchor" href="#omnipeek" aria-label="Permalink to &quot;OmniPeek&quot;">​</a></h2><p>Omnipeek provides real-time analysis for every type of network segment, 802.11, and voice and video over IP and for every level of network traffic.</p><p><a href="https://www.liveaction.com/products/omnipeek-network-protocol-analyzer/" target="_blank" rel="noreferrer">https://www.liveaction.com/products/omnipeek-network-protocol-analyzer/</a></p><h2 id="xarp-arp-spoofing-detection" tabindex="-1">XArp - ARP Spoofing detection <a class="header-anchor" href="#xarp-arp-spoofing-detection" aria-label="Permalink to &quot;XArp - ARP Spoofing detection&quot;">​</a></h2><p>XArp is a security application that uses advanced techniques to detect ARP based attacks. Using active and passive modules XArp detects hackers inside your network. ARP attacks allow an attacker to silently eavesdrop or manipulate all your data that is sent over the network. This include documents, emails, or VoiceIP conversations. ARP spoofing attacks go undetected by firewalls and operating system security: Firewalls do not protect you against ARP based attack.</p><p><a href="http://www.xarp.net/" target="_blank" rel="noreferrer">http://www.xarp.net/</a></p><p><img src="https://qpdownload.com/data/xarp/screenshot/xarp_screenshot_normal_view.png" alt="xarp"></p>',22)]))}const w=a(s,[["render",n]]);export{f as __pageData,w as default};
